#!/usr/bin/env sage
"""
Generate a Lean file certifying the q-expansion of a level-1 LMFDB modular form
via the polynomial-in-(E₄, E₆) framework. Supports arbitrary-degree Hecke fields
by decomposing each K-coefficient as a ℚ-polynomial in the algebraic generator α.

Usage:
    sage scripts/lmfdb_qexp_to_e4e6_v2.sage <weight> [<form_index>] [<output_path>]

Example:
    sage scripts/lmfdb_qexp_to_e4e6_v2.sage 60 0 \
        LeanBridge/ForMathlib/QExpansion/LMFDB_1_60_a_orbit.lean
"""


# This file was *autogenerated* from the file /home/chris/Github/LeanBridge/scripts/lmfdb_qexp_to_e4e6_v2.sage
from sage.all_cmdline import *   # import sage library

_sage_const_1 = Integer(1); _sage_const_0 = Integer(0); _sage_const_12 = Integer(12); _sage_const_5 = Integer(5); _sage_const_4 = Integer(4); _sage_const_6 = Integer(6); _sage_const_10 = Integer(10); _sage_const_3 = Integer(3); _sage_const_2 = Integer(2)
import sys
import os


def fmt_rat(c):
    """Format a rational as Lean syntax."""
    n = c.numerator()
    d = c.denominator()
    if d == _sage_const_1 :
        return f"({n})" if n < _sage_const_0  else f"{n}"
    return f"((-({-n} / {d})))" if n < _sage_const_0  else f"({n} / {d})"


def newform_decomposition(k, form_idx=_sage_const_0 ):
    """Return (poly_coeffs_per_alpha_power, minpoly_coeffs, sturm, qexp_decomp).

    poly_coeffs_per_alpha_power[j] is a list of (a, b, c) where c ∈ ℚ, representing
    the j-th component (coefficient of α^j) of the polynomial expression in (E₄, E₆).

    minpoly_coeffs is [c_0, c_1, ..., c_{d-1}, 1] for x^d + c_{d-1}*x^{d-1} + ... + c_0.

    sturm = ⌊k/12⌋ + 1.

    qexp_decomp[n] is a list of d rationals, the (1, α, α², ...) decomposition of c_n.
    """
    sturm = k // _sage_const_12  + _sage_const_1 
    M = ModularForms(_sage_const_1 , k)
    cusp = M.cuspidal_subspace()
    if cusp.dimension() == _sage_const_0 :
        raise ValueError(f"S_{k} is zero-dimensional")
    forms = cusp.newforms('a')
    f = forms[form_idx]
    K = f.hecke_eigenvalue_field()
    d = K.degree()

    qexp = f.qexp(sturm + _sage_const_5 )
    if qexp[_sage_const_1 ] != _sage_const_0 :
        qexp = qexp / K(qexp[_sage_const_1 ])

    minpoly = K.gen().minpoly()
    minpoly_coeffs = list(minpoly)  # constant first

    basis_pairs = [(a, b) for a in range(k // _sage_const_4  + _sage_const_1 ) for b in range(k // _sage_const_6  + _sage_const_1 )
                   if _sage_const_4  * a + _sage_const_6  * b == k]
    n_basis = len(basis_pairs)

    prec = sturm + _sage_const_5 
    E4 = eisenstein_series_qexp(_sage_const_4 , prec, normalization='constant')
    E6 = eisenstein_series_qexp(_sage_const_6 , prec, normalization='constant')

    R = PowerSeriesRing(K, 'q', prec)
    E4_K = R(E4)
    E6_K = R(E6)
    basis_qexps = [E4_K ** a * E6_K ** b for (a, b) in basis_pairs]

    A = matrix(K, n_basis, n_basis,
               [[K(basis_qexps[j][i]) for j in range(n_basis)]
                for i in range(n_basis)])
    b_vec = vector(K, [K(qexp[i]) for i in range(n_basis)])
    coeffs = A.solve_right(b_vec)

    # Each coeffs[i] is in K, decompose as polynomial in α
    poly_per_power = [[] for _ in range(d)]
    for (a, b), c in zip(basis_pairs, coeffs):
        c_parts = c.list()
        while len(c_parts) < d:
            c_parts.append(QQ(_sage_const_0 ))
        for j in range(d):
            if c_parts[j] != _sage_const_0 :
                poly_per_power[j].append((int(a), int(b), c_parts[j]))

    # Decompose each q-coefficient as well for Sturm certificates
    qexp_decomp = []
    for n in range(prec):
        c_parts = K(qexp[n]).list()
        while len(c_parts) < d:
            c_parts.append(QQ(_sage_const_0 ))
        qexp_decomp.append(c_parts)

    return poly_per_power, minpoly_coeffs, sturm, qexp_decomp, k


def emit_polydata(name, poly):
    """Emit a `def name : List (ℕ × ℕ × ℚ) := [...]`."""
    if not poly:
        return f"def {name} : List (ℕ × ℕ × ℚ) := []"
    entries = ", ".join(f"({a}, {b}, {fmt_rat(c)})" for (a, b, c) in poly)
    return f"def {name} : List (ℕ × ℕ × ℚ) :=\n  [{entries}]"


def emit_form_def(name, weight, poly):
    """Emit `noncomputable def name : ModularForm 𝒮ℒ weight := …`."""
    if not poly:
        return f"noncomputable def {name} : ModularForm 𝒮ℒ {weight} := 0"
    terms = []
    for (a, b, c) in poly:
        terms.append(f"({fmt_rat(c)} : ℂ) • mkMonomForm {a} {b} {weight} (by decide)")
    body = " +\n  ".join(terms)
    return f"noncomputable def {name} : ModularForm 𝒮ℒ {weight} :=\n  {body}"


def emit_bridge_lemma(name, polydata_name, form_name, n_monoms):
    """Emit the bridge lemma `name : qExpansion ↑form = evalEisPS polydata`."""
    if n_monoms == _sage_const_0 :
        return f"""lemma {name} :
    qExpansion 1 ({form_name} : ℍ → ℂ) = evalEisPS {polydata_name} := by
  unfold {form_name} {polydata_name} evalEisPS
  simp [qExpansion_zero]"""

    # For n monomials, alternate coe_add and qExpansion_add (n-1 times),
    # then n smul rewrites and n monom rewrites.
    rw_lines = []
    for _ in range(n_monoms - _sage_const_1 ):
        rw_lines.append("ModularForm.coe_add")
        rw_lines.append("ModularForm.qExpansion_add one_pos one_mem_strictPeriods_SL")
    for _ in range(n_monoms):
        rw_lines.append("ModularForm.IsGLPos.coe_smul")
    for _ in range(n_monoms):
        rw_lines.append("ModularForm.qExpansion_smul one_pos one_mem_strictPeriods_SL")
    for _ in range(n_monoms):
        rw_lines.append("qExpansion_mkMonomForm")
    rw_chain = ",\n    ".join(rw_lines)

    return f"""lemma {name} :
    qExpansion 1 ({form_name} : ℍ → ℂ) = evalEisPS {polydata_name} := by
  unfold {form_name}
  rw [{rw_chain}]
  unfold evalEisPS {polydata_name} monomialEisPS
  simp only [List.foldr_cons, List.foldr_nil, add_zero]
  push_cast
  module"""


def emit_minpoly_lemma(weight, minpoly_coeffs, alpha_name):
    """Emit α def via Classical.choose + minpoly relation lemma."""
    d = len(minpoly_coeffs) - _sage_const_1   # degree
    # minpoly: x^d + c_{d-1} x^{d-1} + ... + c_0 (Sage gives [c_0, c_1, ..., c_{d-1}, 1])
    # Build the polynomial expression in Lean
    poly_terms = []
    for i in range(d, -_sage_const_1 , -_sage_const_1 ):
        c = minpoly_coeffs[i]
        if c == _sage_const_0 :
            continue
        if i == _sage_const_0 :
            poly_terms.append(fmt_rat(c))
        elif i == _sage_const_1 :
            poly_terms.append(f"{fmt_rat(c)} * {alpha_name}")
        else:
            poly_terms.append(f"{fmt_rat(c)} * {alpha_name}^{i}")
    poly_expr = " + ".join(poly_terms) if poly_terms else "0"

    # Build the polynomial as a Lean Polynomial ℚ
    coeffs_str = ", ".join(fmt_rat(c) for c in minpoly_coeffs)

    return f"""/-- Minimal polynomial of α (degree {d}). -/
noncomputable def {alpha_name}_minpoly : Polynomial ℂ :=
  Polynomial.ofFinsupp (Finsupp.mk (List.range {d + _sage_const_1 }).toFinset
    (fun i => match i with
{chr(_sage_const_10 ).join(f"      | {i} => {fmt_rat(c)}" for i, c in enumerate(minpoly_coeffs))}
      | _ => 0)
    (by decide))

/-- α is some root of the degree-{d} minimal polynomial in ℂ.
Defined via classical choice over the algebraic closure ℂ. -/
noncomputable def {alpha_name} : ℂ :=
  ({alpha_name}_minpoly.roots).toFinset.choose (by
    -- ℂ is algebraically closed; minpoly has degree {d} > 0 so has roots
    sorry)

lemma {alpha_name}_is_root : {poly_expr} = 0 := by
  sorry"""


def emit_combined_form(weight, n_pieces, alpha_name):
    """f := f_0 + α • f_1 + α² • f_2 + ... + α^(d-1) • f_(d-1)"""
    terms = ["f_60_part_0"]
    for j in range(_sage_const_1 , n_pieces):
        if j == _sage_const_1 :
            terms.append(f"{alpha_name} • f_60_part_{j}")
        else:
            terms.append(f"{alpha_name}^{j} • f_60_part_{j}")
    body = " +\n  ".join(terms)
    return f"""noncomputable def lmfdb_1_{weight}_a_orbit : ModularForm 𝒮ℒ {weight} :=
  {body}"""


def emit_coeff_decomp(weight, n_pieces, alpha_name):
    """Decomposition lemma: coeff n (qExp ↑f) = sum α^i · coeff n (qExp ↑f_i)."""
    rhs_terms = []
    for j in range(n_pieces):
        coeff_term = f"(PowerSeries.coeff (R := ℂ) n) (qExpansion 1 (f_60_part_{j} : ℍ → ℂ))"
        if j == _sage_const_0 :
            rhs_terms.append(coeff_term)
        elif j == _sage_const_1 :
            rhs_terms.append(f"{alpha_name} * {coeff_term}")
        else:
            rhs_terms.append(f"{alpha_name}^{j} * {coeff_term}")
    rhs = "\n        + ".join(rhs_terms)

    # Proof: alternate coe_add + qExpansion_add (n_pieces - 1 times), then
    # for each non-zero α power: IsGLPos.coe_smul + qExpansion_smul, then simp.
    n_smuls = n_pieces - _sage_const_1   # f_0 isn't smul'd
    rw_lines = []
    for _ in range(n_pieces - _sage_const_1 ):
        rw_lines.append("ModularForm.coe_add")
        rw_lines.append("ModularForm.qExpansion_add one_pos one_mem_strictPeriods_SL")
    for _ in range(n_smuls):
        rw_lines.append("ModularForm.IsGLPos.coe_smul")
    for _ in range(n_smuls):
        rw_lines.append("ModularForm.qExpansion_smul one_pos one_mem_strictPeriods_SL")
    rw_chain = ",\n    ".join(rw_lines)

    return f"""lemma lmfdb_1_{weight}_a_orbit_coeff_decomp (n : ℕ) :
    (PowerSeries.coeff (R := ℂ) n) (qExpansion 1 (lmfdb_1_{weight}_a_orbit : ℍ → ℂ))
      = {rhs} := by
  unfold lmfdb_1_{weight}_a_orbit
  rw [{rw_chain}]
  simp [smul_eq_mul]"""


def emit_sturm_certificate(weight, n, sturm, qexp_decomp_n, n_pieces, alpha_name):
    """One Sturm-bound certificate at index n."""
    # qexp_decomp_n is [c_0, c_1, ..., c_{d-1}] giving f.coeff n = c_0 + α·c_1 + ...
    # We want to prove: (qExp ↑f).coeff n = c_0 + α·c_1 + α²·c_2 + ...
    rhs_parts = []
    for j, c in enumerate(qexp_decomp_n):
        if c == _sage_const_0 :
            continue
        cs = fmt_rat(c)
        if j == _sage_const_0 :
            rhs_parts.append(cs)
        elif j == _sage_const_1 :
            rhs_parts.append(f"{cs} * {alpha_name}")
        else:
            rhs_parts.append(f"{cs} * {alpha_name}^{j}")
    rhs = " + ".join(rhs_parts) if rhs_parts else "0"

    # Build the rw chain: decompose, then each f_i coeff theorem, then list values
    coeff_thm_rws = ", ".join(
        f"f_60_part_{j}_qExpansion_coeff {sturm} {n} (by decide)"
        for j in range(n_pieces))
    list_value_rws = []
    for j in range(n_pieces):
        c = qexp_decomp_n[j] if j < len(qexp_decomp_n) else _sage_const_0 
        list_value_rws.append(
            f"show (evalEisList f_60_part_{j}_polyData {sturm}).getD {n} 0 = "
            f"({fmt_rat(c)} : ℚ) from by decide +kernel"
        )
    list_rws = ",\n    ".join(list_value_rws)

    return f"""example :
    (PowerSeries.coeff (R := ℂ) {n})
      (qExpansion 1 (lmfdb_1_{weight}_a_orbit : ℍ → ℂ)) = {rhs} := by
  rw [lmfdb_1_{weight}_a_orbit_coeff_decomp,
    {coeff_thm_rws},
    {list_rws}]
  push_cast; ring"""


def emit_full(weight, form_idx=_sage_const_0 ):
    poly_per_power, minpoly_coeffs, sturm, qexp_decomp, _ = newform_decomposition(weight, form_idx)
    n_pieces = len(poly_per_power)
    alpha_name = f"α_{weight}"

    # Header
    parts = [f"""import LeanBridge.ForMathlib.QExpansion.Generic
import LeanBridge.ForMathlib.QExpansion.Examples
import Mathlib.FieldTheory.IsAlgClosed.Basic

/-!
# LMFDB level-1 modular form orbit `1.{weight}.a.{{a..}}` (Hecke field degree {n_pieces})

The Hecke field `K = ℚ(α)` is degree {n_pieces} over ℚ. Each `K`-coefficient is decomposed
as `c_0 + c_1 · α + c_2 · α² + … + c_{{{n_pieces - _sage_const_1 }}} · α^{n_pieces - _sage_const_1 }`, giving {n_pieces}
rational pieces. The combined form is `f = f_0 + α · f_1 + … + α^{n_pieces - _sage_const_1 } · f_{{{n_pieces - _sage_const_1 }}}`.

Generated by `scripts/lmfdb_qexp_to_e4e6_v2.sage`.
-/

namespace LeanBridge.QExpansion

open ModularForm EisensteinSeries PowerSeries UpperHalfPlane
open scoped MatrixGroups
"""]

    # α infrastructure
    parts.append(emit_minpoly_lemma(weight, minpoly_coeffs, alpha_name))

    # Polynomial data and form definitions for each α-power piece
    for j in range(n_pieces):
        parts.append(f"\n/-! ## Piece {j}: coefficient of α^{j} -/\n")
        parts.append(emit_polydata(f"f_60_part_{j}_polyData", poly_per_power[j]))
        n_monoms = len(poly_per_power[j])
        parts.append(emit_form_def(f"f_60_part_{j}", weight, poly_per_power[j]))
        parts.append(emit_bridge_lemma(
            f"f_60_part_{j}_qExpansion_eq_evalEisPS",
            f"f_60_part_{j}_polyData",
            f"f_60_part_{j}",
            n_monoms))
        parts.append(f"""theorem f_60_part_{j}_qExpansion_coeff (N n : ℕ) (hn : n < N) :
    (PowerSeries.coeff (R := ℂ) n) (qExpansion 1 (f_60_part_{j} : ℍ → ℂ))
      = ((evalEisList f_60_part_{j}_polyData N).getD n 0 : ℚ) :=
  qexp_coeff_via_E4E6 _ _ f_60_part_{j}_qExpansion_eq_evalEisPS N n hn""")

    # Combined form
    parts.append("\n/-! ## Combined LMFDB form -/\n")
    parts.append(emit_combined_form(weight, n_pieces, alpha_name))
    parts.append(emit_coeff_decomp(weight, n_pieces, alpha_name))

    # Sturm certificates (just first 3 for size)
    parts.append("\n/-! ## Sturm-bound certificates (first 3 for compactness) -/\n")
    for n in range(min(_sage_const_3 , sturm)):
        parts.append(emit_sturm_certificate(
            weight, n, sturm, qexp_decomp[n], n_pieces, alpha_name))

    parts.append("\nend LeanBridge.QExpansion")
    return "\n\n".join(parts)


def main():
    if len(sys.argv) < _sage_const_2 :
        print(__doc__, file=sys.stderr)
        sys.exit(_sage_const_1 )
    weight = int(sys.argv[_sage_const_1 ])
    form_idx = int(sys.argv[_sage_const_2 ]) if len(sys.argv) >= _sage_const_3  else _sage_const_0 
    out_path = sys.argv[_sage_const_3 ] if len(sys.argv) >= _sage_const_4  else None

    code = emit_full(weight, form_idx)

    if out_path:
        os.makedirs(os.path.dirname(os.path.abspath(out_path)), exist_ok=True)
        with open(out_path, 'w') as f:
            f.write(code)
        print(f"Wrote {out_path}", file=sys.stderr)
    else:
        sys.stdout.write(code)


main()

